INSERT INTO destination_activities (id, destination_id, title, description, category, is_seasonal, sort_order, source_row)
VALUES
  ('ACT_0001', 'DST_001', 'Lagoon boat safari (mangroves, birds, sunset)', 'Discover the serene beauty of Negombo Lagoon with a peaceful boat safari through lush mangrove forests. As you glide along calm waters, you''ll witness a rich ecosystem filled with exotic birds, traditional fishing methods, and untouched nature. The experience becomes truly magical during sunset, when the sky reflects golden hues over the lagoon. Creating a perfect setting for photography and relaxation. This is one of the best nature experiences in Negombo for travelers seeking tranquility and scenic beauty.', 'WILDLIFE', FALSE, 1, 3),
  ('ACT_0002', 'DST_001', 'Fish market visit (early morning local experience)', 'Start your day with an authentic cultural experience at Negombo''s bustling fish market, one of the largest in Sri Lanka. Early in the morning, you''ll see fishermen bringing in their fresh catch straight from the ocean, while locals negotiate and trade in a lively atmosphere. The market offers a raw and real glimpse into Sri Lankan coastal life, making it a must-visit for travelers who want to explore local traditions, seafood culture, and daily routines beyond typical tourist spots.', 'GENERAL', FALSE, 2, 4),
  ('ACT_0003', 'DST_001', 'Dutch canal boat ride', 'Step back in time with a relaxing boat ride along the historic Dutch Canal, a colonial-era waterway surrounded by tropical greenery and village life. As you cruise through this scenic route, you''ll observe local homes, fishing communities, and quiet landscapes that showcase the authentic charm of Negombo. This slow-paced experience is perfect for those who enjoy cultural exploration combined with peaceful surroundings.', 'LEISURE', FALSE, 3, 5),
  ('ACT_0004', 'DST_001', 'Beach relaxation / jet skiing', 'Unwind on the golden sandy beaches of Negombo, where the sound of the waves and ocean breeze create the perfect tropical escape. Whether you prefer to relax under the sun or enjoy thrilling water sports like jet skiing, this experience offers something for every traveler. It''s an ideal way to balance your journey with both relaxation and adventure along Sri Lanka''s beautiful west coast.', 'ADVENTURE', FALSE, 4, 6),
  ('ACT_0005', 'DST_001', 'City cycling tour', 'Explore Negombo like a local with a guided cycling tour through charming streets, coastal roads, and traditional neighborhoods. This immersive experience allows you to interact with locals, discover hidden gems, and observe everyday Sri Lankan life up close. From small temples to vibrant markets, cycling offers a unique and eco-friendly way to experience the culture and lifestyle of this coastal town.', 'SPIRITUAL', FALSE, 5, 7),
  ('ACT_0006', 'DST_002', 'Sigiriya Rock Fortress climb (UNESCO site)', 'Step into history as you climb the iconic Sigiriya Rock Fortress, a UNESCO World Heritage Site and one of Sri Lanka''s most famous landmarks. Rising dramatically from the jungle, this ancient royal citadel offers a fascinating journey through frescoes, mirror walls, and lion-shaped gateways. As you reach the summit, you''ll be rewarded with breathtaking panoramic views of lush greenery and surrounding villages. This is a must-do experience for travelers seeking culture, history, and unforgettable views in Sri Lanka.', 'CULTURAL', FALSE, 6, 10),
  ('ACT_0007', 'DST_002', 'Pidurangala Rock sunrise hike', 'For one of the most breathtaking sunrise experiences in Sri Lanka, hike up Pidurangala Rock in the early morning. The short yet adventurous climb takes you through forest paths and rocky terrain, leading to a stunning viewpoint overlooking Sigiriya Rock and the surrounding landscapes. Watching the sunrise from the top, as the sky turns shades of orange and gold, is a truly magical moment and a favorite among photographers and nature lovers.', 'ADVENTURE', FALSE, 7, 11),
  ('ACT_0008', 'DST_002', 'Village safari', 'Experience authentic Sri Lankan village life with a unique cultural safari in the Sigiriya countryside. Travel by traditional bullock cart through rural paths, enjoy a peaceful canoe ride across a scenic lake, and visit a local village home where you''ll learn to cook traditional Sri Lankan dishes. This immersive experience allows you to connect with locals, understand their lifestyle, and enjoy fresh, homemade cuisine, making it one of the most memorable cultural activities in Sri Lanka.', 'WILDLIFE', FALSE, 8, 12),
  ('ACT_0009', 'DST_002', 'Elephant safari in Minneriya / Kaudulla', 'Witness the majestic beauty of wild elephants in their natural habitat with a safari in Minneriya National Park or Kaudulla National Park. These parks are famous for the "Gathering," where large herds of elephants come together near water reservoirs. The safari offers an exciting opportunity to see elephants, birds, and other wildlife up close, making it a must-do for nature enthusiasts and wildlife lovers visiting Sri Lanka.', 'WILDLIFE', FALSE, 9, 13),
  ('ACT_0010', 'DST_002', 'Ayurvedic spa experience', 'Relax and rejuvenate with a traditional Ayurvedic spa experience in Sigiriya, inspired by Sri Lanka''s ancient healing practices. Enjoy herbal treatments, therapeutic massages, and natural oils designed to restore balance to your body and mind. Surrounded by peaceful nature, this wellness experience is perfect after a day of exploration, offering deep relaxation and a touch of luxury to your journey.', 'LEISURE', FALSE, 10, 14),
  ('ACT_0011', 'DST_003', 'Ancient city cycling tour (UNESCO ruins)', 'Explore the timeless beauty of Ancient City of Polonnaruwa with a guided cycling tour through its well-preserved ruins. Ride along quiet pathways surrounded by ancient temples, royal palaces, and sacred monuments dating back over 1,000 years. This eco-friendly experience allows you to fully immerse yourself in the history and scale of the kingdom at your own pace, making it one of the best ways to discover Polonnaruwa''s cultural heritage.', 'SPIRITUAL', FALSE, 11, 16),
  ('ACT_0012', 'DST_003', 'Explore ancient city', 'Step into the golden age of Sri Lankan history as you explore the remarkable ruins of Polonnaruwa, once the thriving capital of the island. Discover iconic sites such as the Royal Palace, sacred quadrangles, and the beautifully carved Buddha statues at Gal Vihara. Surrounded by lush greenery and peaceful surroundings, this experience offers a deep cultural and spiritual connection, perfect for travelers interested in history, architecture, and heritage.', 'SPIRITUAL', FALSE, 12, 17),
  ('ACT_0013', 'DST_004', 'Sacred city temple tour', 'Discover the spiritual heart of Sri Lanka with a visit to the Sacred City of Anuradhapura, one of the oldest continuously inhabited cities in the world. The highlight of this sacred journey is the revered Sri Maha Bodhi, believed to be grown from a cutting of the original Bodhi tree under which Buddha attained enlightenment. Surrounded by ancient monasteries and peaceful surroundings, this experience offers a profound connection to Sri Lanka''s rich Buddhist heritage.', 'SPIRITUAL', FALSE, 13, 21),
  ('ACT_0014', 'DST_004', 'Ruwanwelisaya & Jetavanaramaya stupas', 'Witness the grandeur of ancient Sri Lankan architecture as you visit the iconic Ruwanwelisaya and Jetavanaramaya, two of the most impressive stupas in the world. These massive white domes stand as symbols of devotion and engineering brilliance, attracting pilgrims and travelers alike. Walking around these sacred monuments, especially during prayer times, allows you to experience the powerful spiritual energy and timeless beauty of Anuradhapura.', 'SPIRITUAL', FALSE, 14, 22),
  ('ACT_0015', 'DST_004', 'Local pilgrimage experience', 'Immerse yourself in the authentic spiritual life of Sri Lanka by joining a local pilgrimage experience in Anuradhapura. Observe devotees dressed in white offering flowers, lighting oil lamps, and practicing ancient rituals passed down through generations. This unique cultural interaction allows you to witness genuine faith and devotion, providing a deeper understanding of Sri Lanka''s traditions and spiritual lifestyle.', 'SPIRITUAL', FALSE, 15, 23),
  ('ACT_0016', 'DST_005', 'Whale & dolphin watching (seasonal)', 'Embark on an unforgettable ocean adventure in Trincomalee with a whale and dolphin watching experience (best during the season). Cruise into the deep blue waters of the Indian Ocean, where you may witness majestic blue whales, playful dolphins, and other marine life in their natural habitat. This thrilling yet peaceful journey is perfect for nature lovers and offers one of the most unique wildlife experiences in Sri Lanka.', 'WILDLIFE', TRUE, 16, 26),
  ('ACT_0017', 'DST_005', 'Snorkeling at Pigeon Island', 'Discover the vibrant underwater world of Pigeon Island National Park, one of the best snorkeling spots in Sri Lanka. Swim among colorful coral reefs, tropical fish, and even reef sharks in crystal-clear waters. This protected marine park offers an easy and enjoyable snorkeling experience for both beginners and experienced travelers, making it a must-visit for anyone exploring Trincomalee.', 'WILDLIFE', FALSE, 17, 27),
  ('ACT_0018', 'DST_005', 'Visit Koneswaram Temple (cliff views) & Visit Fort Frederick', 'Visit the sacred Koneswaram Temple, dramatically perched on a cliff overlooking the ocean. Known as the "Temple of a Thousand Pillars," it offers breathtaking panoramic views and deep spiritual significance. Combine this with a visit to Fort Frederick, a historic site surrounded by greenery and home to friendly deer roaming freely. This experience blends culture, history, and stunning coastal scenery.', 'SPIRITUAL', FALSE, 18, 28),
  ('ACT_0019', 'DST_005', 'Nilaveli beach relaxation', 'Unwind on the pristine shores of Nilaveli Beach, famous for its soft white sand and calm turquoise waters. Far from the crowds, this tranquil beach is perfect for sunbathing, swimming, or simply enjoying the peaceful coastal atmosphere. Whether you''re looking to relax or capture picture-perfect moments, Nilaveli offers one of the most beautiful beach experiences in Sri Lanka.', 'LEISURE', FALSE, 19, 29),
  ('ACT_0020', 'DST_006', 'Munneswaram & Manavari temple', 'Explore the spiritual heritage of Chilaw with a visit to the sacred Munneswaram Temple and Manavari Temple. These ancient temples are deeply connected to the Ramayana legend and attract devotees from India and around the world. Surrounded by peaceful surroundings and rich history, this experience offers a meaningful cultural and spiritual journey, perfect for those seeking divine connection and heritage exploration.', 'SPIRITUAL', FALSE, 20, 31),
  ('ACT_0021', 'DST_006', 'Lagoon fishing experience', 'Enjoy a unique and authentic local experience with traditional fishing in the calm lagoons of Chilaw. Join local fishermen as they demonstrate age-old techniques, giving you a hands-on opportunity to try fishing yourself. Set against a backdrop of mangroves and serene waters, this activity offers a glimpse into the daily life of coastal communities and a chance to connect with nature in a peaceful setting.', 'WILDLIFE', FALSE, 21, 32),
  ('ACT_0022', 'DST_006', 'Quiet beach relaxation', 'Escape the crowds and unwind on the untouched beaches of Chilaw, where tranquility meets natural beauty. With soft sands, gentle waves, and a calm atmosphere, these beaches are perfect for relaxation, long walks, and enjoying the sunset. Ideal for travelers seeking a peaceful coastal retreat, Chilaw offers a refreshing break away from busy tourist hotspots.', 'LEISURE', FALSE, 22, 33),
  ('ACT_0023', 'DST_007', 'Dambulla Cave Temple (UNESCO)', 'Discover the awe-inspiring beauty of the Dambulla Cave Temple, one of the most well-preserved cave temple complexes in Asia. Carved into a rock, this sacred site features stunning Buddha statues, intricate wall paintings, and centuries-old murals that tell stories of Sri Lanka''s Buddhist heritage. As you explore the peaceful caves, surrounded by panoramic views of the countryside, you''ll experience a deep sense of spirituality and history.', 'SPIRITUAL', FALSE, 23, 38),
  ('ACT_0024', 'DST_007', 'Golden Buddha Temple visit', 'Visit the iconic Golden Temple of Dambulla, home to a towering golden Buddha statue that welcomes visitors from afar. This impressive landmark combines modern architecture with religious significance and serves as an important spiritual center. The temple complex also houses a museum showcasing Buddhist art and history, making it a perfect stop for cultural exploration and photography.', 'SPIRITUAL', FALSE, 24, 39),
  ('ACT_0025', 'DST_007', 'Ayurvedic Spice garden tour', 'Engage your senses with a visit to a traditional spice garden in Dambulla, where you''ll learn about Sri Lanka''s world-famous herbs and spices. Walk through lush gardens filled with cinnamon, cardamom, pepper, and medicinal plants, while experts explain their uses in Ayurveda and local cuisine. This interactive experience often includes demonstrations and herbal treatments, offering both knowledge and relaxation in a natural setting.', 'LEISURE', FALSE, 25, 40),
  ('ACT_0026', 'DST_008', 'Visit Temple of the Tooth', 'Experience the spiritual heart of Sri Lanka with a visit to the sacred Temple of the Sacred Tooth Relic, one of the most revered Buddhist sites in the world. Located within the royal palace complex, this temple houses a relic of Lord Buddha and attracts thousands of pilgrims daily. Witness traditional rituals, explore the beautiful architecture, and feel the deep spiritual atmosphere that makes Kandy a must-visit destination.', 'SPIRITUAL', FALSE, 26, 43),
  ('ACT_0027', 'DST_008', 'Cultural dance show', 'Immerse yourself in Sri Lanka''s vibrant traditions with an energetic cultural dance performance in Kandy. Featuring traditional Kandyan dances, fire walking, and drumming, this lively show reflects the island''s rich heritage and artistic expression. It''s a captivating experience that brings Sri Lankan culture to life through rhythm, color, and movement.', 'CULTURAL', FALSE, 27, 44),
  ('ACT_0028', 'DST_008', 'Kandy lake evening walk', 'Enjoy a peaceful stroll around the scenic Kandy Lake, located in the heart of the city. Surrounded by lush hills and historic landmarks, the lake offers a calm and romantic atmosphere, especially during sunset. This relaxing walk is perfect for unwinding after a day of sightseeing while taking in the beauty of Kandy.', 'LEISURE', FALSE, 28, 45),
  ('ACT_0029', 'DST_008', 'Gem museum visit', 'Discover the fascinating world of Sri Lanka''s precious stones with a visit to a gem museum in Kandy. Learn about the island''s rich history in gem mining, see rare stones such as sapphires and rubies, and understand the craftsmanship behind fine jewelry. This experience is both educational and exciting, especially for those interested in luxury and local artistry.', 'CULTURAL', FALSE, 29, 46),
  ('ACT_0030', 'DST_008', 'Peradeniya Botanical Garden', 'Explore the lush beauty of Royal Botanic Gardens, Peradeniya, one of the finest botanical gardens in Asia. Spread over vast grounds, it features a stunning collection of orchids, palm avenues, bamboo groves, and exotic plants from around the world. This serene environment is perfect for nature lovers, photography enthusiasts, and anyone seeking a refreshing escape.', 'GENERAL', FALSE, 30, 47),
  ('ACT_0031', 'DST_008', 'Ayurvedic Spice garden tour', 'Enhance your wellness journey with a visit to a traditional spice garden near Kandy. Discover the secrets of Sri Lanka''s natural herbs and spices, including cinnamon, cloves, and nutmeg, widely used in Ayurvedic treatments. Guided tours often include demonstrations and relaxing herbal therapies, offering a perfect blend of knowledge, culture, and rejuvenation.', 'LEISURE', FALSE, 31, 48),
  ('ACT_0032', 'DST_009', 'Tea plantation & factory visit', 'Step into the heart of Sri Lanka''s tea country in Nuwara Eliya with a visit to lush tea plantations and a working factory. Walk through rolling green hills where world-famous Ceylon tea is grown, and witness the fascinating process from leaf to cup. Enjoy freshly brewed tea while soaking in breathtaking views, making this a must-do experience for nature lovers and culture enthusiasts.', 'GENERAL', FALSE, 32, 50),
  ('ACT_0033', 'DST_009', 'Enjoy Train ride', 'Enjoy one of the most beautiful train journeys in the world through the misty hills of Sri Lanka. Travel between Kandy and Nuwara Eliya (Nanu Oya station), passing through tea estates, tunnels, and picturesque villages. This iconic train ride offers stunning panoramic views and unforgettable moments, making it a highlight for photographers and travelers alike.', 'ADVENTURE', FALSE, 33, 51),
  ('ACT_0034', 'DST_009', 'Visit Ramboda waterfall', 'Witness the majestic beauty of Ramboda Falls, one of the tallest and most scenic waterfalls in the country. Surrounded by lush greenery and misty mountains, this cascading waterfall creates a refreshing and tranquil atmosphere. It''s an ideal stop for nature lovers and a perfect photo opportunity during your journey through the hill country.', 'GENERAL', FALSE, 34, 52),
  ('ACT_0035', 'DST_009', 'Explore Hanuman temple', 'Visit the sacred Sri Bhakta Hanuman Temple, an important site connected to the Ramayana legend. Surrounded by mountains and tea plantations, this temple holds deep spiritual significance for Hindu travelers. The peaceful environment and mythological connection make it a meaningful cultural and religious experience.', 'SPIRITUAL', FALSE, 35, 53),
  ('ACT_0036', 'DST_009', 'Visit Gregory Lake', 'Relax and unwind at Gregory Lake, a scenic spot surrounded by hills and cool climate. Enjoy activities such as boat rides, cycling, or simply a leisurely walk along the lakeside. This popular attraction offers a perfect blend of relaxation and recreation in the heart of Nuwara Eliya.', 'LEISURE', FALSE, 36, 54),
  ('ACT_0037', 'DST_009', 'Visit to local Strawberry farms', 'Experience a delightful visit to strawberry farms in Nuwara Eliya, where the cool climate creates ideal conditions for fresh produce. Walk through the farms, taste freshly picked strawberries, and enjoy desserts made from local ingredients. This charming experience is especially loved by families and couples.', 'GENERAL', FALSE, 37, 55),
  ('ACT_0038', 'DST_009', 'Visit to Ambewela farm', 'Discover the picturesque Ambewela Farm, often called "Little New Zealand" of Sri Lanka. Surrounded by rolling grasslands, this farm is home to high-quality dairy production and offers a peaceful countryside experience. Visitors can explore the farm, see animals, and enjoy fresh dairy products in a scenic setting.', 'GENERAL', FALSE, 38, 56),
  ('ACT_0039', 'DST_009', 'Explore Horton Plains', 'Explore the breathtaking landscapes of Horton Plains National Park, a UNESCO-listed natural reserve known for its unique biodiversity. Walk through misty grasslands and cloud forests to reach famous viewpoints like World''s End and Baker''s Falls. This nature experience is perfect for those seeking scenic beauty and a refreshing escape into the wild.', 'WILDLIFE', FALSE, 39, 57),
  ('ACT_0040', 'DST_009', 'Trip to Little England cottages', 'Experience the colonial charm of Nuwara Eliya, often referred to as "Little England," with its cozy cottages, red-brick houses, and cool climate. A visit to these charming properties offers a glimpse into the British-era lifestyle, surrounded by beautifully maintained gardens and scenic landscapes. It''s a perfect experience for relaxation, photography, and enjoying the peaceful hill country atmosphere.', 'LEISURE', FALSE, 40, 58),
  ('ACT_0041', 'DST_010', 'Visit Nine Arch Bridge visit', 'Witness one of Sri Lanka''s most iconic landmarks, the Nine Arch Bridge, a stunning colonial-era railway bridge surrounded by lush jungle and tea plantations. Time your visit to see a train crossing the bridge for the perfect photo opportunity. This picturesque spot is a must-visit for travelers seeking Instagram-worthy views and a touch of history in Ella.', 'CULTURAL', FALSE, 41, 60),
  ('ACT_0042', 'DST_010', 'Enjoy Ravana Pool Club', 'Relax in style at the popular Ravana Pool Club, where luxury meets tropical vibes. Enjoy refreshing cocktails, infinity pool views, music, and a vibrant atmosphere surrounded by greenery. It''s the perfect place to unwind, socialize, and enjoy a premium leisure experience in Ella.', 'LEISURE', FALSE, 42, 61),
  ('ACT_0043', 'DST_010', 'Little Adam''s Peak hike', 'Enjoy a scenic and easy hike to Little Adam''s Peak, offering breathtaking panoramic views of the surrounding mountains and tea plantations. The well-marked trail makes it accessible for all fitness levels, and the sunrise or sunset views from the top are truly unforgettable. This is one of the best short hikes in Ella for nature lovers.', 'ADVENTURE', FALSE, 43, 62),
  ('ACT_0044', 'DST_010', 'Flying Ravana zipline', 'Add some adrenaline to your trip with the thrilling Flying Ravana Zipline, one of the fastest zip lines in South Asia. Glide over lush green hills and enjoy stunning aerial views of Ella''s landscape. This exciting experience is perfect for adventure seekers looking for a unique perspective of the region.', 'ADVENTURE', FALSE, 44, 63),
  ('ACT_0045', 'DST_010', 'Explore Ella town', 'Discover the laid-back charm of Ella, a vibrant town surrounded by nature. Stroll through its cozy streets filled with cafes, boutique shops, and friendly locals. The relaxed atmosphere, combined with cool weather and scenic views, makes Ella a favorite destination for travelers from around the world.', 'LEISURE', FALSE, 45, 64),
  ('ACT_0046', 'DST_010', 'Ella Rock hike', 'Challenge yourself with a rewarding hike to Ella Rock, one of the most scenic viewpoints in the region. The trail takes you through railway tracks, tea plantations, and forest paths, leading to breathtaking views from the summit. This hike is perfect for adventure lovers seeking both excitement and natural beauty.', 'ADVENTURE', FALSE, 46, 65),
  ('ACT_0047', 'DST_010', 'Café hopping', 'Indulge in Ella''s vibrant café culture by exploring its many unique and stylish spots. From scenic mountain-view cafés to cozy hidden gems in Ella, you can enjoy freshly brewed coffee, delicious international cuisine, and relaxed vibes. This experience is perfect for unwinding, socializing, and capturing beautiful travel moments.', 'LEISURE', FALSE, 47, 66),
  ('ACT_0048', 'DST_011', 'Jeep safari in Yala National Park', 'Embark on an exciting wildlife adventure in Yala National Park, the most famous national park in Sri Lanka, known for having one of the highest densities of leopards in the world. Travel through diverse landscapes, lagoons, and open grasslands in a private jeep, guided by experienced trackers. Along the way, you may encounter elephants, crocodiles, sloth bears, and a wide variety of bird species. This thrilling safari experience offers a perfect blend of nature, adventure, and unforgettable moments in the wild.', 'WILDLIFE', FALSE, 48, 68),
  ('ACT_0049', 'DST_012', 'Kataragama temple visit', 'Visit the sacred Kataragama Temple, one of the most important pilgrimage sites in Sri Lanka, revered by Buddhists, Hindus, and Muslims alike. Dedicated to Lord Skanda (Kataragama Deviyo), this spiritual complex attracts devotees from across the country and beyond. Surrounded by a peaceful yet vibrant atmosphere, the temple offers a unique opportunity to experience Sri Lanka''s rich religious harmony and devotion.', 'SPIRITUAL', FALSE, 49, 70),
  ('ACT_0050', 'DST_012', 'Evening pooja experience', 'Witness the powerful energy of the evening pooja at Kataragama Temple, where rituals are performed with fire, drums, and chanting. As the sun sets, the temple comes alive with devotion, creating an intense and emotional atmosphere. This spiritual ceremony offers a rare glimpse into traditional worship practices and leaves visitors with a deeply moving and unforgettable experience.', 'SPIRITUAL', FALSE, 50, 71),
  ('ACT_0051', 'DST_012', 'Explore Spiritual rituals', 'Immerse yourself in the unique spiritual traditions of Kataragama, where devotees perform ancient rituals as acts of faith and gratitude. From offerings and prayers to symbolic practices passed down through generations, this experience allows you to witness authentic devotion up close. It''s a profound cultural encounter that provides deeper insight into Sri Lanka''s spiritual life and beliefs.', 'SPIRITUAL', FALSE, 51, 72),
  ('ACT_0052', 'DST_013', 'Silent beach relaxation', 'Unwind on the serene shores of Tangalle, where untouched beaches and crystal-clear waters create the perfect setting for relaxation. Far from crowded tourist spots, Tangalle offers a peaceful atmosphere ideal for sunbathing, long walks, and enjoying the soothing sound of the ocean. This hidden gem is perfect for travelers seeking tranquility and a true tropical escape.', 'LEISURE', FALSE, 52, 76),
  ('ACT_0053', 'DST_013', 'Visit Rekawa turtle conservation project', 'Experience a unique wildlife encounter at the Rekawa Turtle Conservation Project, one of the most important turtle nesting sites in Sri Lanka. Visit in the evening to witness sea turtles coming ashore to lay their eggs in a natural and protected environment. This responsible and educational experience offers a rare opportunity to observe marine life up close while supporting conservation efforts.', 'WILDLIFE', FALSE, 53, 77),
  ('ACT_0054', 'DST_013', 'Lagoon kayaking', 'Explore the calm and scenic lagoons near Tangalle with a relaxing kayaking experience. Paddle through mangrove forests, observe birdlife, and enjoy the peaceful surroundings at your own pace. This eco-friendly activity is perfect for nature lovers looking to connect with the quiet beauty of Sri Lanka''s coastal ecosystems.', 'WILDLIFE', FALSE, 54, 78),
  ('ACT_0055', 'DST_014', 'Whale watching tours', 'Set out on an unforgettable ocean adventure from Mirissa, one of the best places in the world for whale watching. Cruise into the deep waters of the Indian Ocean, where you may spot majestic blue whales, sperm whales, and playful dolphins in their natural habitat. This early morning experience is a must for nature lovers and offers a rare opportunity to witness marine giants up close.', 'WILDLIFE', FALSE, 55, 80),
  ('ACT_0056', 'DST_014', 'Explore Parrot Rock', 'Take a short walk across the shallow waters to reach Parrot Rock, a small hill offering panoramic views of Mirissa Beach. This hidden viewpoint is perfect for capturing stunning photos of the coastline, especially during sunrise or sunset. It''s a quick yet rewarding experience for travelers exploring the area.', 'LEISURE', FALSE, 56, 81),
  ('ACT_0057', 'DST_014', 'Coconut Tree Hill sunset', 'Visit the iconic Coconut Tree Hill, one of the most photographed spots in Sri Lanka. With a row of tall coconut palms overlooking the ocean, this location offers breathtaking sunset views and a perfect tropical vibe. It''s an ideal place to relax, take photos, and enjoy the beauty of Sri Lanka''s southern coast.', 'LEISURE', FALSE, 57, 82),
  ('ACT_0058', 'DST_014', 'Explore Mirissa Beach & Secret beach', 'Enjoy the lively atmosphere of Mirissa Beach, known for its golden sands, turquoise waters, and beachfront cafés. For a more secluded experience, visit Secret Beach Mirissa, a quiet bay perfect for swimming and relaxing away from the crowds. Together, these spots offer the perfect mix of energy and tranquility.', 'LEISURE', FALSE, 58, 83),
  ('ACT_0059', 'DST_014', 'Beach nightlife', 'Experience the vibrant nightlife of Mirissa, where beachside bars and restaurants come alive after sunset. Enjoy music, seafood dinners, fire shows, and lively parties right by the ocean. This energetic atmosphere makes Mirissa a favorite destination for young travelers and those looking to enjoy Sri Lanka''s coastal nightlife.', 'LEISURE', FALSE, 59, 84),
  ('ACT_0060', 'DST_014', 'Enjoy Surfing experience', 'Ride the waves along the الساحل of Mirissa, where gentle breaks make it an ideal spot for both beginners and intermediate surfers. With warm waters and professional instructors available, surfing in Mirissa is a fun and exciting way to experience the ocean. It''s a must-try activity for adventure seekers visiting the south coast.', 'ADVENTURE', FALSE, 60, 85),
  ('ACT_0061', 'DST_015', 'Enjoy Surfing experience', 'Ride the gentle waves of Weligama, one of the best beginner-friendly surfing destinations in Sri Lanka. With its wide sandy bay and consistent waves, Weligama offers the perfect conditions for learning and improving your surfing skills. Professional instructors and surf schools are readily available, making it an exciting and accessible experience for all levels.', 'ADVENTURE', FALSE, 61, 87),
  ('ACT_0062', 'DST_015', 'Stilt fishermen experience', 'Witness the iconic tradition of stilt fishing along the الساحل near Weligama, a unique cultural practice found only in Sri Lanka. Perched on wooden stilts above the shallow waters, fishermen demonstrate their age-old fishing technique, creating a truly memorable and photogenic scene. This experience offers insight into local heritage and is a must-see for cultural explorers.', 'CULTURAL', FALSE, 62, 88),
  ('ACT_0063', 'DST_015', 'Beach cafés & chill vibe', 'Relax and soak in the laid-back atmosphere of Weligama, known for its trendy beach cafés and relaxed coastal lifestyle. Enjoy freshly brewed coffee, healthy meals, and ocean views while listening to the sound of the waves. This chill vibe makes Weligama a favorite spot for digital nomads, couples, and travelers looking to unwind by the sea.', 'LEISURE', FALSE, 63, 89),
  ('ACT_0064', 'DST_016', 'Advanced surfing', 'Ride powerful waves along Ahangama, a hotspot for experienced surfers seeking consistent reef and point breaks. Known for its stronger waves and less crowded surf spots, Ahangama offers the perfect setting to challenge your skills and elevate your surfing experience. This destination attracts surf enthusiasts from around the world looking for both adventure and a relaxed coastal atmosphere.', 'ADVENTURE', FALSE, 64, 92),
  ('ACT_0065', 'DST_016', 'Boutique café hopping', 'Explore the stylish café scene of Ahangama, known for its trendy boutique cafés and creative spaces. From artisan coffee to healthy brunch options, each café offers a unique ambiance blending modern design with tropical charm. This experience is perfect for travelers who enjoy good food, aesthetic interiors, and a relaxed social vibe by the ocean.', 'LEISURE', FALSE, 65, 93),
  ('ACT_0066', 'DST_016', 'Instagram-style beach photography spots', 'Capture stunning travel moments at some of the most photogenic locations in Ahangama. From palm-lined beaches and oceanfront villas to unique coastal viewpoints, Ahangama is a paradise for photography lovers and content creators. Whether it''s sunrise, sunset, or candid beach shots, every corner offers a perfect backdrop for your Instagram-worthy memories.', 'LEISURE', FALSE, 66, 94),
  ('ACT_0067', 'DST_017', 'Jungle Beach visit', 'Escape to the hidden paradise of Jungle Beach, a secluded bay surrounded by lush greenery and calm turquoise waters. Accessible through a short jungle trail, this peaceful beach offers a perfect retreat away from the crowds. Ideal for swimming, relaxing, and enjoying nature, Jungle Beach is a must-visit for travelers seeking a quiet and scenic coastal experience.', 'LEISURE', FALSE, 67, 96),
  ('ACT_0068', 'DST_017', 'Enjoy Snorkeling experience', 'Discover the underwater beauty of Unawatuna with an exciting snorkeling experience in its clear, shallow waters. Swim among colorful fish, coral reefs, and diverse marine life in one of Sri Lanka''s best beginner-friendly snorkeling spots. This activity is perfect for families, couples, and anyone looking to explore the ocean in a fun and easy way.', 'GENERAL', FALSE, 68, 97),
  ('ACT_0069', 'DST_017', 'Enjoy Diving experience', 'Explore deeper into the ocean with a diving experience in Unawatuna, where you can discover vibrant coral gardens, shipwrecks, and rich marine biodiversity. Guided by professional instructors, this experience caters to both beginners and certified divers. It''s an unforgettable adventure for those looking to experience Sri Lanka''s underwater world up close.', 'ADVENTURE', FALSE, 69, 98),
  ('ACT_0070', 'DST_017', 'Rumassala Peace pagoda', 'Visit the serene Japanese Peace Pagoda Rumassala, located on a hill overlooking the океан. This peaceful Buddhist stupa offers breathtaking panoramic views of the coastline and surrounding जंगल. Known for its calm and spiritual atmosphere, it''s an ideal spot for meditation, sunset views, and quiet reflection away from the busy beach scene.', 'SPIRITUAL', FALSE, 70, 99),
  ('ACT_0071', 'DST_017', 'Beach parties & restaurants', 'Enjoy the lively atmosphere of Unawatuna, famous for its beachfront restaurants, live music, and vibrant beach parties. As the sun sets, the shoreline transforms into a social hub where you can enjoy fresh seafood, cocktails, and entertainment right by the ocean. This experience is perfect for travelers looking to combine relaxation with nightlife.', 'LEISURE', FALSE, 71, 100),
  ('ACT_0072', 'DST_018', 'Galle Fort walking tour (UNESCO)', 'Step into history with a walking tour of the iconic Galle Fort, a beautifully preserved colonial fortress built by the Portuguese and later expanded by the Dutch. Wander through cobblestone streets lined with charming villas, boutique hotels, and historic landmarks. This immersive experience offers a perfect blend of culture, architecture, and seaside charm, making it one of the most unique destinations in Sri Lanka.', 'CULTURAL', FALSE, 72, 102),
  ('ACT_0073', 'DST_018', 'Lighthouse & sunset views', 'Enjoy breathtaking coastal views at the historic Galle Lighthouse, located within the fort overlooking the океан. As the sun begins to set, the sky transforms into vibrant shades of orange and pink, creating a magical atmosphere along the fort walls. This is one of the best sunset spots on the south coast, perfect for photography and relaxation.', 'CULTURAL', FALSE, 73, 103),
  ('ACT_0074', 'DST_018', 'Shopping (boutiques, handicrafts)', 'Explore the vibrant shopping scene inside Galle Fort, where you''ll find unique boutiques, art galleries, and local handicraft stores. From handmade jewelry and textiles to souvenirs and designer pieces, shopping here offers a perfect mix of tradition and modern style. It''s an ideal experience for travelers looking to take home something special from Sri Lanka.', 'CULTURAL', FALSE, 74, 104),
  ('ACT_0075', 'DST_018', 'Café culture (very popular with Europeans)', 'Experience the lively café culture of Galle Fort, known for its trendy cafés, artisan coffee, and international cuisine. With its European-style ambiance and coastal views, the fort has become a favorite spot for travelers from around the world. Whether you''re enjoying brunch, fresh seafood, or a sunset coffee, this experience perfectly combines relaxation with a sophisticated vibe.', 'CULTURAL', FALSE, 75, 105),
  ('ACT_0076', 'DST_019', 'Water sports (jet ski, banana boat, parasailing)', 'Experience the thrill of water sports in Bentota, one of the best destinations in Sri Lanka for adventure activities. From high-speed jet skiing to fun-filled banana boat rides and breathtaking parasailing over the океан, there''s something for every adrenaline seeker. This exciting experience perfectly combines fun, adventure, and stunning coastal views.', 'ADVENTURE', FALSE, 76, 108),
  ('ACT_0077', 'DST_019', 'Bentota river safari', 'Explore the rich biodiversity of the Bentota River with a scenic boat safari through mangroves and calm waterways. As you cruise along the river, you may spot crocodiles, exotic birds, and local wildlife while visiting small islands and cinnamon plantations. This relaxing yet adventurous journey offers a unique perspective of Sri Lanka''s natural beauty.', 'WILDLIFE', FALSE, 77, 109),
  ('ACT_0078', 'DST_019', 'Turtle hatchery visit', 'Visit a turtle conservation center near Bentota and learn about efforts to protect endangered sea turtles. Observe baby turtles, understand the hatching process, and even witness their release into the океан (depending on timing). This meaningful and educational experience is perfect for families and wildlife lovers, offering a closer connection to marine conservation in Sri Lanka.', 'WILDLIFE', FALSE, 78, 110),
  ('ACT_0079', 'DST_019', 'Kande Viharaya temple', 'Step into a powerful spiritual experience at the majestic Kande Viharaya Temple, home to one of the tallest seated Buddha statues in the world. As you walk through the sacred temple grounds, you feel a deep sense of peace, devotion, and cultural richness. The sound of chanting, the scent of incense, and the golden Buddha create a truly emotional connection with Sri Lanka''s Buddhist heritage.', 'SPIRITUAL', FALSE, 79, 111),
  ('ACT_0080', 'DST_019', 'Madu river safari & Cinnamon islands', 'Discover the magical world of the Madu River, where nature unfolds in its purest form. A boat safari through winding mangroves takes you past small islands, hidden temples, and untouched ecosystems. You will witness exotic birds, water monitors, and peaceful village life along the riverbanks - a journey that feels like entering a living natural paradise filled with calm and wonder.', 'WILDLIFE', FALSE, 80, 112),
  ('ACT_0081', 'DST_020', 'Colombo city tour (Gangaramaya, Independence Square)', 'Discover the dynamic capital of Sri Lanka with a guided tour of Colombo, where modern life blends seamlessly with cultural heritage. Visit iconic landmarks such as the sacred Gangaramaya Temple and the historic Independence Memorial Hall. This experience offers a perfect introduction to the city''s history, architecture, and spiritual significance.', 'SPIRITUAL', FALSE, 81, 114),
  ('ACT_0082', 'DST_020', 'Shopping (One Galle Face, Pettah market)', 'Enjoy a diverse shopping experience in Colombo, from modern malls to traditional markets. Visit One Galle Face Mall for international brands, dining, and ocean views, or explore the bustling streets of Pettah Market for local goods, textiles, and a vibrant street shopping atmosphere. This blend of old and new makes Colombo a shopper''s paradise.', 'LEISURE', FALSE, 82, 115),
  ('ACT_0083', 'DST_020', 'Rooftop dining & nightlife', 'Experience the energetic nightlife of Colombo with rooftop dining and stylish lounges overlooking the city skyline and океан. Enjoy gourmet cuisine, creative cocktails, and live music in a sophisticated setting. Whether it''s a romantic dinner or a night out with friends, Colombo offers some of the best nightlife experiences in Sri Lanka.', 'LEISURE', FALSE, 83, 116),
  ('ACT_0084', 'DST_020', 'Street food tour', 'Dive into the flavors of Colombo with an exciting street food tour through its lively neighborhoods. Taste local favorites like kottu roti, hoppers, and fresh seafood while exploring hidden food spots loved by locals. This culinary journey offers a delicious way to experience Sri Lanka''s culture, traditions, and everyday life.', 'GENERAL', FALSE, 84, 117),
  ('ACT_0085', 'DST_021', 'Kalutara Bodhiya temple visit', 'Visit the sacred Kalutara Bodhiya, one of the most revered Buddhist sites in Sri Lanka, beautifully located along the Kalu Ganga river. This historic temple is home to a sacred Bodhi tree believed to be a descendant of the original tree under which Buddha attained enlightenment. Surrounded by a peaceful atmosphere, it offers a deeply spiritual experience where visitors can observe rituals, offer prayers, and connect with Sri Lanka''s rich religious heritage.', 'SPIRITUAL', FALSE, 85, 119),
  ('ACT_0086', 'DST_021', 'Beach relaxation', 'Unwind on the tranquil beaches of Kalutara, where golden sands and gentle waves create the perfect setting for relaxation. Less crowded than other coastal destinations, Kalutara offers a calm and refreshing escape ideal for sunbathing, leisurely walks, and enjoying the soothing ocean breeze. It''s the perfect place to slow down and end your journey on a peaceful note.', 'LEISURE', FALSE, 86, 120),
  ('ACT_0087', 'DST_022', 'Dolphin watching', 'Embark on an unforgettable marine adventure in Kalpitiya, one of the best places in Sri Lanka for dolphin watching. Cruise into the open ocean where you can witness large pods of spinner dolphins jumping and playing alongside the boat. This early morning experience offers breathtaking views of the sea and a magical connection with marine wildlife in their natural habitat.', 'WILDLIFE', FALSE, 87, 123),
  ('ACT_0088', 'DST_022', 'Kite surfing', 'Experience world-class kite surfing in Kalpitiya, known for its consistent winds and ideal lagoon conditions. Whether you are a beginner or an advanced rider, Kalpitiya offers perfect flat waters and professional instructors to elevate your skills. This destination is considered one of the top kite surfing spots in Asia, attracting adventure seekers from around the globe.', 'WILDLIFE', FALSE, 88, 124),
  ('ACT_0089', 'DST_022', 'Lagoon kayaking', 'Explore the peaceful lagoons of Kalpitiya with a relaxing kayaking experience through mangroves and calm waters. Paddle at your own pace while observing birdlife and enjoying the untouched natural surroundings. This eco-friendly activity is perfect for travelers looking to connect with nature and enjoy a quiet escape.', 'WILDLIFE', FALSE, 89, 125),
  ('ACT_0090', 'DST_023', 'Calm shallow beach swimming', 'Enjoy the peaceful waters of Pasikuda, famous for its exceptionally calm and shallow sea. Stretching far into the ocean, the gentle waters make it one of the safest beaches in Sri Lanka for swimming, especially for families and non-swimmers. With soft golden and crystal-clear water, Pasikuda offers a perfect setting for relaxation and carefree beach time.', 'LEISURE', FALSE, 90, 127),
  ('ACT_0091', 'DST_023', 'Snorkeling', 'Discover the underwater beauty of Pasikuda with a relaxing snorkeling experience in its clear, shallow waters. Explore colorful marine life and coral formations while enjoying excellent visibility and calm conditions. This easy and enjoyable activity is ideal for beginners and anyone looking to experience Sri Lanka''s marine world in a safe and peaceful environment.', 'LEISURE', FALSE, 91, 128),
  ('ACT_0092', 'DST_024', 'Koggala lake boat safari', 'Explore the tranquil waters of Koggala Lake with a scenic boat safari through mangroves and small islands. As you cruise across the lake, you''ll encounter rich birdlife, traditional fishing scenes, and untouched natural beauty. This relaxing journey offers a unique blend of nature and culture, making it one of the most peaceful experiences on Sri Lanka''s south coast.', 'WILDLIFE', FALSE, 92, 131),
  ('ACT_0093', 'DST_024', 'Cinnamon island visit', 'Visit a traditional cinnamon island in Koggala Lake and discover how Sri Lanka''s world-famous cinnamon is cultivated and processed. Watch local artisans demonstrate peeling techniques and learn about the history of this valuable spice. This authentic cultural experience provides a deeper understanding of local livelihoods while offering a chance to enjoy the serene island atmosphere.', 'CULTURAL', FALSE, 93, 132),
  ('ACT_0094', 'DST_025', 'Surfing', 'Experience the legendary waves of Arugam Bay, known as one of the best surf points in the world. The long, clean right-hand point breaks create the perfect ride for both beginners and professional surfers. As you stand on the board, feel the warm ocean breeze, endless blue horizon, and pure adrenaline that makes Arugam Bay a true surfer''s paradise in Sri Lanka.', 'ADVENTURE', FALSE, 94, 134),
  ('ACT_0095', 'DST_025', 'Lagoon safari (crocodiles, elephants)', 'Escape into the hidden wilderness just minutes away from the beach. A lagoon safari in Arugam Bay takes you through calm mangrove waters where nature reveals its raw beauty. Watch crocodiles resting silently along the banks, elephants moving gracefully nearby, and flocks of exotic birds flying over the lagoon - a peaceful yet thrilling wildlife experience in untouched nature.', 'WILDLIFE', FALSE, 95, 135),
  ('ACT_0096', 'DST_025', 'Beach parties', 'When the sun sets, Arugam Bay transforms into a vibrant coastal celebration. Seasonal beach parties bring together travelers from all over the world under the stars, with live music, fire dances, and oceanfront DJ nights. The sound of waves blends with the rhythm of music, creating unforgettable tropical nights filled with energy, freedom, and connection.', 'CULTURAL', TRUE, 96, 136),
  ('ACT_0097', 'DST_025', 'Yoga & wellness retreats', 'Slow down and reconnect with yourself in the peaceful rhythm of Arugam Bay. Surrounded by palm trees and ocean views, yoga and wellness retreats offer daily sessions of yoga, meditation, and healing practices. It is the perfect place to restore balance, breathe deeply, and experience inner peace while listening to the calming sound of the Indian Ocean.', 'WELLNESS', FALSE, 97, 137)
